def ping_go2(host: str = GO2_ONBOARD_IP, count: int = 2) -> bool:
    try:
        r = subprocess.run(
            ["ping", "-c", str(count), "-W", "2", host],
            capture_output=True,
            timeout=15,
        )
        return r.returncode == 0
    except (FileNotFoundError, subprocess.TimeoutExpired):
        return False


def resolve_go2_interface(
    requested: str | None = None,
