"""Day 2 Plan Tuner — copy a baseline plan and apply leg overrides."""
import json, sys, shutil, os

def tune_plan(baseline_path: str, output_path: str, overrides: dict) -> None:
    """overrides = {leg_index: {dx: 0.4, dyaw: 0.7}} — leg_index is 0-based."""
    with open(baseline_path) as f:
        plan = json.load(f)
    for leg_idx_str, fields in overrides.items():
        leg_idx = int(leg_idx_str)
        if leg_idx < len(plan.get("legs", [])):
            plan["legs"][leg_idx].update(fields)
    plan["_tuned_from"] = os.path.basename(baseline_path)
    with open(output_path, "w") as f:
        json.dump(plan, f, indent=2)
    print(f"[TUNED] {output_path}")

if __name__ == "__main__":
    # Usage: python lab04_tune_plan.py baseline_patrol_plan.json tuned_patrol_plan.json --set 1:dyaw:0.7
    args = sys.argv[1:]
    overrides = {}
    for a in args:
        if a.startswith("--set"):
            continue
        if ":" in a:
            leg_idx, rest = a.split(":", 1)
            key, val = rest.split(":", 1)
            overrides.setdefault(leg_idx, {})[key] = float(val)
    tune_plan(args[0], args[1], overrides)
